  const myTrainers = (trainers||[]).filter(tr=>(tr.tids||[]).includes(player.mainTid));

  const [p,setP] = useState({...player});
  const [showTrend,setShowTrend] = useState(false);
  const up = f => setP(prev => ({...prev,...f}));
